/**
 * Generated by `createschema subscription.SubscriptionContext 'organization:Relationship:Organization:CASCADE; subscriptionPlan:Relationship:SubscriptionPlan:PROTECT; startAt:DateTimeUtc; endAt:DateTimeUtc; basePrice:Decimal; calculatedPrice:Decimal; appliedRules:Json; isTrial:Checkbox;'`
 */

const dayjs = require('dayjs')

const { userIsAdmin } = require('@open-condo/keystone/access')
const { GQLError, GQLErrorCode: { BAD_USER_INPUT } } = require('@open-condo/keystone/errors')
const { historical, versioned, uuided, tracked, softDeleted, dvAndSender, analytical } = require('@open-condo/keystone/plugins')
const { GQLListSchema, find } = require('@open-condo/keystone/schema')

const { ACTIVATE_SUBSCRIPTION_TYPE } = require('@condo/domains/onboarding/constants/userHelpRequest')
const { UserHelpRequest } = require('@condo/domains/onboarding/utils/serverSchema')
const { ORGANIZATION_OWNED_FIELD } = require('@condo/domains/organization/schema/fields')
const access = require('@condo/domains/subscription/access/SubscriptionContext')
const { SUBSCRIPTION_CONTEXT_STATUS, SUBSCRIPTION_CONTEXT_STATUSES } = require('@condo/domains/subscription/constants')

const ERRORS = {
    END_DATE_MUST_BE_AFTER_START_DATE: {
        code: BAD_USER_INPUT,
        type: 'END_DATE_MUST_BE_AFTER_START_DATE',
        message: 'endAt must be after startAt',
    },
    ORGANIZATION_TYPE_MISMATCH: {
        code: BAD_USER_INPUT,
        type: 'ORGANIZATION_TYPE_MISMATCH',
        message: 'Organization type must match SubscriptionPlan organizationType',
    },
    OVERLAPPING_SUBSCRIPTION: {
        code: BAD_USER_INPUT,
        type: 'OVERLAPPING_SUBSCRIPTION',
        message: 'Cannot create subscription with the same plan and isTrial value on overlapping dates',
    },
    TRIAL_CANNOT_HAVE_PRICING_RULE: {
        code: BAD_USER_INPUT,
        type: 'TRIAL_CANNOT_HAVE_PRICING_RULE',
        message: 'Trial subscription cannot have subscriptionPlanPricingRule',
    },
    TRIAL_CANNOT_HAVE_INVOICE: {
        code: BAD_USER_INPUT,
        type: 'TRIAL_CANNOT_HAVE_INVOICE',
        message: 'Trial subscription cannot have invoice',
    },
}


const SubscriptionContext = new GQLListSchema('SubscriptionContext', {
    schemaDoc: 'Subscription context linking organization to a subscription plan with calculated pricing. When changing subscription plan, a new context must be created',
    fields: {

        organization: {
            ...ORGANIZATION_OWNED_FIELD,
            schemaDoc: 'Organization that has this subscription',
        },

        subscriptionPlan: {
            schemaDoc: 'Subscription plan selected by the organization',
            type: 'Relationship',
            ref: 'SubscriptionPlan',
            isRequired: true,
            knexOptions: { isNotNullable: true },
            kmigratorOptions: { null: false, on_delete: 'models.PROTECT' },
            access: {
                read: true,
                create: true,
                update: false,
            },
        },

        startAt: {
            schemaDoc: 'Subscription start date',
            type: 'CalendarDay',
            isRequired: true,
            access: {
                read: true,
                create: true,
                update: false,
            },
        },

        endAt: {
            schemaDoc: 'Subscription end date',
            type: 'CalendarDay',
            isRequired: true,
            access: {
                read: true,
                create: true,
                update: false,
            },
        },

        subscriptionPlanPricingRule: {
            schemaDoc: 'Pricing rule that was used for this subscription',
            type: 'Relationship',
            ref: 'SubscriptionPlanPricingRule',
            isRequired: false,
            knexOptions: { isNotNullable: false },
            kmigratorOptions: { null: true, on_delete: 'models.SET_NULL' },
            access: {
                read: true,
                create: true,
                update: false,
            },
        },

        invoice: {
            schemaDoc: 'Invoice for this subscription payment. Populated from payment invoice',
            type: 'Relationship',
            ref: 'Invoice',
            isRequired: false,
            knexOptions: { isNotNullable: false },
            kmigratorOptions: { null: true, on_delete: 'models.SET_NULL' },
            access: {
                read: true,
                create: true,
                update: false,
            },
        },

        isTrial: {
            schemaDoc: 'Whether this is a trial subscription. Trial subscriptions provide temporary free access to the plan features for a limited period (defined by SubscriptionPlan.trialDays)',
            type: 'Checkbox',
            defaultValue: false,
            isRequired: true,
            access: {
                read: true,
                create: true,
                update: false,
            },
        },

        status: {
            schemaDoc: 'Subscription context status. CREATED - context created but not yet active, DONE - context is fully processed and active, ERROR - processing failed',
            type: 'Select',
            options: SUBSCRIPTION_CONTEXT_STATUSES.join(', '),
            defaultValue: SUBSCRIPTION_CONTEXT_STATUS.CREATED,
            isRequired: true,
            access: {
                read: true,
                create: true,
                update: true,
            },
        },

        bindingId: {
            schemaDoc: 'Saved card token on acquiring side used for subscription auto-payments. The presence of this value indicates that auto-payments are enabled',
            type: 'Text',
            isRequired: false,
            access: {
                read: true,
                create: true,
                update: true,
            },
        },

        frozenPaymentInfo: {
            schemaDoc: 'Frozen payment information at the time of subscription context creation. Includes payment method details, invoice information, and pricing rule ID',
            type: 'Json',
            isRequired: false,
            extendGraphQLTypes: [
                'type PaymentMethod { bindingId: String!, paymentSystem: String!, cardNumber: String!, expiration: String!, bankName: String!, bankCountryCode: String! }',
                'type InvoiceRow { name: String, count: String, price: String, toPay: String }',
                'type FrozenInvoice { id: String, rows: [InvoiceRow], toPay: String }',
                'type FrozenPaymentInfo { paymentMethod: PaymentMethod, invoice: FrozenInvoice, pricingRuleId: String }',
            ],
            graphQLReturnType: 'FrozenPaymentInfo',
            graphQLAdminFragment: '{ paymentMethod { bindingId paymentSystem cardNumber expiration bankName bankCountryCode } invoice { id rows { name count price toPay } toPay } pricingRuleId }',
            access: {
                read: true,
                create: userIsAdmin,
                update: false,
            },
        },

        daysRemaining: {
            schemaDoc: 'Number of days remaining in the subscription. Calculated from server time. Returns 0 if subscription has expired',
            type: 'Virtual',
            graphQLReturnType: 'Int',
            resolver: (item) => {
                if (!item.endAt) return null

                const now = dayjs()
                const endAt = dayjs(item.endAt)
                const diffInHours = endAt.diff(now, 'hour', true)
                const diffDays = Math.ceil(diffInHours / 24)

                if (diffDays <= 0) return 0

                return diffDays
            },
        },

    },
    hooks: {
        validateInput: async ({ resolvedData, existingItem, context, operation }) => {
            const startAt = resolvedData.startAt || existingItem?.startAt
            const endAt = resolvedData.endAt || existingItem?.endAt

            if (startAt && endAt && startAt >= endAt) {
                throw new GQLError(ERRORS.END_DATE_MUST_BE_AFTER_START_DATE, context)
            }

            const organizationId = resolvedData.organization
            const subscriptionPlanId = resolvedData.subscriptionPlan

            if (organizationId && subscriptionPlanId) {
                const orgIdToValidate = organizationId || existingItem?.organization
                const planIdToValidate = subscriptionPlanId || existingItem?.subscriptionPlan

                const [organization] = await find('Organization', { id: orgIdToValidate, deletedAt: null })
                const [subscriptionPlan] = await find('SubscriptionPlan', { id: planIdToValidate, deletedAt: null })

                if (organization && subscriptionPlan) {
                    if (organization.type !== subscriptionPlan.organizationType) {
                        throw new GQLError(ERRORS.ORGANIZATION_TYPE_MISMATCH, context)
                    }
                }
            }

            const isTrial = resolvedData.isTrial !== undefined ? resolvedData.isTrial : existingItem?.isTrial
            const subscriptionPlanPricingRule = resolvedData.subscriptionPlanPricingRule
            const invoice = resolvedData.invoice

            if (isTrial && subscriptionPlanPricingRule) {
                throw new GQLError(ERRORS.TRIAL_CANNOT_HAVE_PRICING_RULE, context)
            }

            if (isTrial && invoice) {
                throw new GQLError(ERRORS.TRIAL_CANNOT_HAVE_INVOICE, context)
            }

            const recurrentPaymentEnabled = resolvedData.recurrentPaymentEnabled
            const hasPricingRule = subscriptionPlanPricingRule || existingItem?.subscriptionPlanPricingRule

            if (recurrentPaymentEnabled && (isTrial || !hasPricingRule)) {
                throw new GQLError(ERRORS.RECURRENT_PAYMENT_REQUIRES_PAID_SUBSCRIPTION, context)
            }

            if (operation === 'create') {
                const organizationId = resolvedData.organization
                const subscriptionPlanId = resolvedData.subscriptionPlan
                const isTrial = !!resolvedData.isTrial
                const startAt = resolvedData.startAt
                const endAt = resolvedData.endAt

                if (organizationId && subscriptionPlanId && startAt && endAt) {
                    const overlappingSubscriptions = await find('SubscriptionContext', {
                        organization: { id: organizationId },
                        subscriptionPlan: { id: subscriptionPlanId },
                        isTrial,
                        deletedAt: null,
                        startAt_lt: endAt,
                        endAt_gt: startAt,
                    })

                    if (overlappingSubscriptions.length > 0) {
                        throw new GQLError(ERRORS.OVERLAPPING_SUBSCRIPTION, context)
                    }
                }
            }
        },
        afterChange: async ({ operation, updatedItem, context }) => {
            // Only delete pending requests when a non-trial subscription context is created
            if (operation === 'create' && !updatedItem.isTrial) {
                const organizationId = updatedItem.organization
                
                // Soft delete all pending UserHelpRequests for this organization with activateSubscription type
                const pendingRequests = await find('UserHelpRequest', {
                    organization: { id: organizationId },
                    type: ACTIVATE_SUBSCRIPTION_TYPE,
                    deletedAt: null,
                })

                for (const request of pendingRequests) {
                    await UserHelpRequest.update(context, request.id, {
                        dv: 1,
                        sender: updatedItem.sender,
                        deletedAt: new Date().toISOString(),
                    })
                }
            }
        },
    },
    plugins: [uuided(), versioned(), tracked(), softDeleted(), dvAndSender(), historical(), analytical()],
    access: {
        read: access.canReadSubscriptionContexts,
        create: access.canManageSubscriptionContexts,
        update: access.canManageSubscriptionContexts,
        delete: false,
        auth: true,
    },
})

module.exports = {
    SubscriptionContext,
}
